async (params, browser) => {
  // Open SoundCloud charts
  await browser.open(`https://soundcloud.com/charts/top?genre=soundcloud%3Agenres%3A${params.genre}`)

  // Wait for chart to load
  await browser.waitForSelector('.chartTrack, [class*=\'chartTrack\'], [class*=\'soundList__item\'], .sc-list-nostyle li', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract trending tracks
  const trending_data = await browser.evaluate(`const tracks = []; const trackEls = document.querySelectorAll('.chartTrack, [class*="chartTrack"], .soundList__item, [class*="soundList__item"]'); for (let i = 0; i < Math.min(trackEls.length, 20); i++) { const el = trackEls[i]; const titleEl = el.querySelector('.soundTitle__title span, a[class*="soundTitle"] span, [class*="chartTrack__title"]'); const artistEl = el.querySelector('.soundTitle__username, a[class*="soundTitle__username"], [class*="chartTrack__username"]'); const playsEl = el.querySelector('[class*="playbackCount"], [title*="plays"]'); const likesEl = el.querySelector('[class*="likeCount"]'); const linkEl = el.querySelector('a[class*="soundTitle__title"], a.soundTitle__title'); const imgEl = el.querySelector('.image__full, .sc-artwork img, img'); tracks.push({ rank: i + 1, title: titleEl ? titleEl.textContent.trim() : '', artist: artistEl ? artistEl.textContent.trim() : '', plays: playsEl ? playsEl.textContent.trim() : '', likes: likesEl ? likesEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { genre: params.genre || 'all-music', trending_count: tracks.length, tracks: tracks, url: window.location.href }`)

  return trending_data
}
